// Parse incoming message from Evolution API
const body = $input.first().json.body || $input.first().json;

// Extract message data
const data = body.data || body;
const instance = body.instance || '';
const event = body.event || 'messages.upsert';

// Process messages.upsert (incoming) and send.message (secretary from phone)
if (event !== 'messages.upsert' && event !== 'send.message') {
  return [{ json: { skip: true, reason: 'not a message event' } }];
}

// send.message = could be secretary from phone or Lara via API
if (event === 'send.message') {
  const source = data.source || '';
  // Skip if sent by API (Lara) — only process if from phone (android/web/ios)
  if (source === 'unknown' || source === '' || source === 'api') {
    return [{ json: { skip: true, reason: 'send.message from API (Lara)' } }];
  }
  const sendPhone = (data.remoteJid || data.key?.remoteJid || '').replace('@s.whatsapp.net', '').replace(/@.*/, '');
  const sendText = data.message?.conversation || data.message?.extendedTextMessage?.text || '';
  const sendJid = data.remoteJid || data.key?.remoteJid || '';
  if (sendText) {
    return [{ json: { skip: false, phone: sendPhone, text: sendText, contentType: 'secretary_reply', caption: '', mediaType: '', pushName: '', messageId: data.key?.id || '', remoteJid: sendJid, instance: instance, timestamp: new Date().toISOString() } }];
  }
  return [{ json: { skip: true, reason: 'send.message without text' } }];
}

const msg = data.message || data;
const key = data.key || {};

// Detect outgoing messages from phone (secretary replied manually)
if (key.fromMe) {
  // Extract recipient phone - try multiple sources
  let recipientPhone = '';
  if (key.remoteJid && key.remoteJid.includes('@s.whatsapp.net')) {
    recipientPhone = key.remoteJid.replace('@s.whatsapp.net', '');
  } else if (key.senderPn) {
    recipientPhone = key.senderPn.replace('@s.whatsapp.net', '');
  } else if (data.pushName && key.remoteJid) {
    // LID format - try to find phone from participant
    recipientPhone = (key.participant || key.remoteJid || '').replace(/@.*/, '');
  }
  const outText = msg.conversation || msg.extendedTextMessage?.text || '';
  // Flag as secretary reply if has text
  if (outText) {
    return [{ json: { skip: false, phone: recipientPhone || '', text: outText, contentType: 'secretary_reply', caption: '', mediaType: '', pushName: '', messageId: key.id || '', remoteJid: key.remoteJid || '', instance: instance, timestamp: new Date().toISOString() } }];
  }
  return [{ json: { skip: true, reason: 'outgoing message without text' } }];
}

// GUARD: Skip group messages
if (key.remoteJid && (key.remoteJid.includes('@g.us') || key.remoteJid.includes('@broadcast'))) {
  return [{ json: { skip: true, reason: 'group or broadcast message' } }];
}

// Extract phone: prefer senderPn (LID format), fallback to remoteJid
let phone = '';
if (key.senderPn) {
  phone = key.senderPn.replace('@s.whatsapp.net', '');
} else if (key.remoteJid && key.remoteJid.includes('@s.whatsapp.net')) {
  phone = key.remoteJid.replace('@s.whatsapp.net', '');
} else if (body.sender) {
  phone = body.sender.replace('@s.whatsapp.net', '');
} else {
  phone = (key.remoteJid || '').replace(/@.*/, '');
}

const messageId = key.id || '';
const pushName = data.pushName || msg.pushName || '';
const remoteJid = key.remoteJid || '';

// Detect content type
let contentType = 'text';
let text = msg.conversation || msg.extendedTextMessage?.text || '';
let caption = '';
let mediaType = '';

if (msg.imageMessage) {
  contentType = 'image';
  caption = msg.imageMessage.caption || '';
  text = caption || '[imagem recebida]';
  mediaType = msg.imageMessage.mimetype || 'image/jpeg';
} else if (msg.audioMessage) {
  contentType = 'audio';
  text = '[audio recebido]';
  mediaType = msg.audioMessage.mimetype || 'audio/ogg';
} else if (msg.videoMessage) {
  contentType = 'video';
  caption = msg.videoMessage.caption || '';
  text = caption || '[video recebido]';
  mediaType = msg.videoMessage.mimetype || 'video/mp4';
} else if (msg.documentMessage) {
  contentType = 'document';
  text = '[documento recebido: ' + (msg.documentMessage.fileName || 'arquivo') + ']';
  mediaType = msg.documentMessage.mimetype || '';
} else if (msg.stickerMessage) {
  contentType = 'sticker';
  text = '[sticker recebido]';
}

if (!phone) {
  return [{ json: { skip: true, reason: 'no phone' } }];
}

// GUARD: Truncar mensagens muito longas (economia de tokens)
if (text.length > 2000) {
  text = text.substring(0, 2000) + '... [mensagem truncada]';
}

return [{
  json: {
    skip: false,
    phone: phone,
    text: text,
    contentType: contentType,
    caption: caption,
    mediaType: mediaType,
    pushName: pushName,
    messageId: messageId,
    remoteJid: remoteJid,
    instance: instance,
    timestamp: new Date().toISOString()
  }
}];

// Download media from Evolution API if needed
const parseData = $('Parse Message').first().json;
const ctxData = $input.first().json;

const contentType = parseData.contentType || 'text';
let mediaBase64 = null;
let mediaContentType = null;

if (contentType === 'image' || contentType === 'audio') {
  try {
    const result = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://n8n_evolution-api:8080/chat/getBase64FromMediaMessage/Mih',
      headers: {
        'apikey': '429683C4C977415CAAFCCE10F7D57E11',
        'Content-Type': 'application/json'
      },
      body: {
        message: {
          key: {
            remoteJid: parseData.remoteJid,
            id: parseData.messageId,
            fromMe: false
          }
        }
      },
      json: true
    });
    if (result && result.base64) {
      const b64 = result.base64;
      const commaIdx = b64.indexOf(',');
      mediaBase64 = commaIdx >= 0 ? b64.substring(commaIdx + 1) : b64;
      mediaContentType = parseData.mediaType || (contentType === 'image' ? 'image/jpeg' : 'audio/ogg');
    }
  } catch (e) {
    // Media download failed, continue without it
  }
}

return [{
  json: {
    ...ctxData,
    mediaBase64: mediaBase64,
    mediaContentType: mediaContentType,
    contentType: contentType,
    audioTranscript: null
  }
}];

// Check for pre-defined responses (zero tokens)
const _msg = $('Parse Message').first().json;
const _ctx = $input.first().json;
const _msgCount = _ctx.message_count || 0;
const _leadName = _ctx.lead?.name || _msg.pushName || '';
const _firstName = _leadName ? _leadName.split(' ')[0] : '';
const _funnel = _ctx.lead?.funnel || null;
const _isNew = _msgCount <= 1;

// MSG 1: First contact — fixed response (zero tokens)
if (_msgCount === 0) {
  var greeting = 'Que bom ter voce aqui! Sou a Lara, assessora da Dra. Mirian de Paula.\n\nFico muito feliz que tenha tomado essa decisao. Vai ser um prazer te acompanhar nesse primeiro contato com a clinica.\n\nPra comecarmos, me conta seu nome?';
  return [{ json: { phone: _msg.phone, leadId: _ctx.lead?.id || null, conversationId: _ctx.conversation_id || null, systemPrompt: '', messages: [], persona: 'onboarder', messageText: _msg.text, instance: _msg.instance, fixedResponse: greeting } }];
}

// MSG 2: After name — fixed response with photo (zero tokens)
if (_msgCount === 1 && _firstName) {
  var welcome = 'Prazer, ' + _firstName + '!\n\nOlha o tipo de resultado que a Dra. Mirian entrega:\n\n[FOTO:geral]\n\nMe conta: o que mais te incomoda hoje? O que voce gostaria de melhorar?';
  return [{ json: { phone: _msg.phone, leadId: _ctx.lead?.id || null, conversationId: _ctx.conversation_id || null, systemPrompt: '', messages: [], persona: 'onboarder', messageText: _msg.text, instance: _msg.instance, fixedResponse: welcome } }];
}

// Build Claude prompt with lead context
const msg = $('Parse Message').first().json;
const ctx = $input.first().json;

const lead = ctx.lead || {};
const history = ctx.history || [];
const persona = lead.ai_persona || 'onboarder';
const funnel = lead.funnel || ctx.funnel || null;
const isReturning = ctx.is_returning || false;
const msgCount = ctx.message_count || 0;
const convCount = ctx.conversation_count || 0;
const lastAiMsg = ctx.last_ai_message || null;
const mediaBase64 = ctx.mediaBase64 || null;
const mediaContentType = ctx.mediaContentType || null;
const contentType = ctx.contentType || msg.contentType || 'text';

// Build conversation history for Claude
const messages = history.map(h => ({
  role: h.direction === 'inbound' ? 'user' : 'assistant',
  content: h.content
}));

// Add current message (with image if available)
if (contentType === 'image' && mediaBase64) {
  // Send image + caption to Claude Vision
  const content = [
    {
      type: 'image',
      source: {
        type: 'base64',
        media_type: mediaContentType || 'image/jpeg',
        data: mediaBase64
      }
    },
    {
      type: 'text',
      text: (msg.caption ? msg.caption + '\n\n' : '') + 'O paciente enviou esta foto. OBRIGATÓRIO: Descreva especificamente o que você vê na imagem (região do rosto, tipo de queixa visível, características). NÃO ignore a imagem. Baseie sua resposta no que observa na foto. Lembre-se: você NÃO dá diagnóstico, mas pode descrever o que vê e dizer que a Dra. Mirian vai avaliar pessoalmente.'
    }
  ];
  messages.push({ role: 'user', content: content });
} else if (contentType === 'audio') {
  // Audio: check if transcription is available from Download Media
  var audioTranscript = ctx.audioTranscript || null;
  if (audioTranscript) {
    messages.push({ role: 'user', content: '[O paciente enviou um audio. Transcricao: ' + audioTranscript + ']' });
  } else {
    messages.push({ role: 'user', content: '[O paciente enviou um audio que nao foi possivel transcrever. Responda educadamente pedindo que envie como texto, explicando que voce funciona melhor com mensagens escritas.]' });
  }
} else {
  messages.push({ role: 'user', content: msg.text });
}

