const prevData = $('Build Claude Prompt').first().json;
if (prevData.fixedResponse) {
  const parseData = $('Parse Message').first().json;
  let fixedPhoto = null;
  let fixedClean = prevData.fixedResponse;
  const fixedMatch = prevData.fixedResponse.match(/\[FOTO:([^\]]+)\]/);
  if (fixedMatch) {
    fixedPhoto = fixedMatch[1].trim();
    fixedClean = prevData.fixedResponse.replace(/\[FOTO:[^\]]+\]/g, '').replace(/\n{3,}/g, '\n\n').trim();
  }
  return [{ json: { phone: prevData.phone, leadId: prevData.leadId, conversationId: prevData.conversationId, aiResponse: fixedClean, tokensUsed: 0, tags: [], persona: prevData.persona, instance: prevData.instance, userMessage: prevData.messageText, detectedName: parseData.pushName || null, photoQueixa: fixedPhoto } }];
}

// Extract Claude response and detect tags
const claudeRes = $input.first().json;
const parseData = $('Parse Message').first().json;

const aiResponse = claudeRes.content?.[0]?.text || 'Desculpe, tive um problema. Pode repetir?';
const tokensUsed = (claudeRes.usage?.input_tokens || 0) + (claudeRes.usage?.output_tokens || 0);

// Detect conversation tags from AI response
const tags = [];
const lower = aiResponse.toLowerCase();
if (lower.includes('horário') || lower.includes('agendar') || lower.includes('marcar')) tags.push('pronto_agendar');
if (lower.includes('vou confirmar com a dra')) tags.push('precisa_humano');

// Detect from user message
const userMsg = prevData.messageText.toLowerCase();
if (userMsg.includes('preço') || userMsg.includes('valor') || userMsg.includes('quanto custa')) tags.push('perguntou_preco');
if (userMsg.includes('caro') || userMsg.includes('não tenho')) tags.push('objecao_preco');
if (userMsg.includes('reclamaç') || userMsg.includes('insatisf') || userMsg.includes('problema')) tags.push('precisa_humano');

// Detect patient name from user message
// Common patterns: "meu nome é X", "sou o/a X", "me chamo X", "é a/o X"
let detectedName = null;
const namePatterns = [
  /(?:meu nome [eé]|me chamo|sou (?:o|a|eu)?\s*)\s+([A-ZÀ-Ú][a-zà-ú]+(?:\s+[A-ZÀ-Ú][a-zà-ú]+)*)/i,
  /^(?:(?:oi|ol[aá]|bom dia|boa (?:tarde|noite)),?\s*)?(?:(?:sou|aqui [eé])\s+(?:o|a)?\s*)([A-ZÀ-Ú][a-zà-ú]+)/i
];
for (const pattern of namePatterns) {
  const match = prevData.messageText.match(pattern);
  if (match && match[1]) {
    detectedName = match[1].trim();
    break;
  }
}

// Use pushName as fallback if no lead name exists
const leadName = detectedName || (prevData.leadId ? null : parseData.pushName) || null;

// Detect [FOTO:queixa] tag in AI response
let photoQueixa = null;
let cleanResponse = aiResponse;
const fotoMatch = aiResponse.match(/\[FOTO:([^\]]+)\]/);
if (fotoMatch) {
  photoQueixa = fotoMatch[1].trim();
  cleanResponse = aiResponse.replace(/\[FOTO:[^\]]+\]/g, '').replace(/\n{3,}/g, '\n\n').trim();
}

return [{
  json: {
    phone: prevData.phone,
    leadId: prevData.leadId,
    conversationId: prevData.conversationId,
    aiResponse: cleanResponse,
    tokensUsed: tokensUsed,
    tags: tags,
    persona: prevData.persona,
    instance: prevData.instance,
    userMessage: prevData.messageText,
    detectedName: leadName,
    photoQueixa: photoQueixa
  }
}];

// Send photo if [FOTO:queixa] was detected
const data = $('Process AI Response').first().json;
const photoQueixa = data.photoQueixa;

if (!photoQueixa) {
  return [{ json: { photoSent: false } }];
}

try {
  // Fetch ALL photos from bank
  const allMedia = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://oqboitkpcvuaudouwvkl.supabase.co/rest/v1/rpc/wa_get_media',
    headers: {
      'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0',
      'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0',
      'Content-Type': 'application/json'
    },
    body: {},
    json: true
  });

  if (!allMedia || allMedia.length === 0) {
    return [{ json: { photoSent: false, queixa: photoQueixa } }];
  }

  // Get previously sent photos in this conversation
  let sentUrls = [];
  if (data.conversationId) {
    try {
      const convData = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://oqboitkpcvuaudouwvkl.supabase.co/rest/v1/rpc/wa_inbox_conversation',
        headers: {
          'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0',
          'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0',
          'Content-Type': 'application/json'
        },
        body: { p_conversation_id: data.conversationId },
        json: true
      });
      const msgs = convData?.messages || [];
      sentUrls = msgs.filter(m => m.content && m.content.includes('Resultado real')).map(m => m.content);
    } catch(e) {}
  }

  // Filter: prefer matching queixa, exclude already sent
  let candidates = allMedia.filter(m => m.queixas && m.queixas.includes(photoQueixa) && !sentUrls.some(s => s.includes(m.filename)));

  // Fallback: any photo not yet sent
  if (candidates.length === 0) {
    candidates = allMedia.filter(m => !sentUrls.some(s => s.includes(m.filename)));
  }

  // Last fallback: any photo
  if (candidates.length === 0) {
    candidates = allMedia;
  }

  // Send 2 photos
  const shuffled = candidates.sort(() => Math.random() - 0.5);
  const toSend = shuffled.slice(0, 2);
  const sentPhotos = [];

  for (const photo of toSend) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://n8n_evolution-api:8080/message/sendMedia/Mih',
        headers: {
          'apikey': '429683C4C977415CAAFCCE10F7D57E11',
          'Content-Type': 'application/json'
        },
        body: {
          number: data.phone,
          mediatype: 'image',
          media: photo.url,
          caption: photo.caption || 'Resultado real - Dra. Mirian de Paula'
        },
        json: true
      });
      sentPhotos.push(photo.url);
    } catch(e) {}
  }

  // Log photos to Supabase so they appear in inbox
  const sbHeaders = {
    'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0',
    'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0',
    'Content-Type': 'application/json'
  };
  for (const photoUrl of sentPhotos) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://oqboitkpcvuaudouwvkl.supabase.co/rest/v1/wa_messages',
        headers: sbHeaders,
        body: {
          conversation_id: data.conversationId,
          direction: 'outbound',
          content: photoUrl,
          content_type: 'image',
          sender_type: 'ai'
        },
        json: true
      });
    } catch(e) {}
  }

  // Send follow-up question AFTER the photos
  let followUpText = null;
  if (sentPhotos.length > 0) {
    const questions = [
      'Voce se imagina com esse tipo de resultado?',
      'Lindo ne? E o que voce esta procurando?',
      'O que acha desse tipo de transformacao?',
      'Um resultado assim e o que voce busca?'
    ];
    followUpText = questions[Math.floor(Math.random() * questions.length)];
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://n8n_evolution-api:8080/message/sendText/Mih',
        headers: {
          'apikey': '429683C4C977415CAAFCCE10F7D57E11',
          'Content-Type': 'application/json'
        },
        body: { number: data.phone, text: followUpText },
        json: true
      });
      // Log follow-up to Supabase
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://oqboitkpcvuaudouwvkl.supabase.co/rest/v1/wa_messages',
        headers: sbHeaders,
        body: {
          conversation_id: data.conversationId,
          direction: 'outbound',
          content: followUpText,
          content_type: 'text',
          sender_type: 'ai'
        },
        json: true
      });
    } catch(e) {}
  }

  return [{ json: { photoSent: true, photoCount: sentPhotos.length, queixa: photoQueixa, followUp: followUpText } }];
} catch(e) {
  return [{ json: { photoSent: false, queixa: photoQueixa, error: e.message } }];
}

// Merge guard result with lead context
const guard = $input.first().json;
const ctx = $('Download Media').first().json;

return [{ json: { ...ctx, guard_action: guard.action, guard_blocks: guard.blocks, guard_flags: guard.flags, guard_msgs_today: guard.msgs_today } }];
